/**
 * 全局配置文件
 * 统一管理 API 地址等配置项
 */

// API 基础地址，从环境变量读取
// 生产环境使用空字符串（相对路径），开发环境使用 localhost:5008
export const API_BASE_URL = process.env.VUE_APP_API_BASE_URL !== undefined 
  ? process.env.VUE_APP_API_BASE_URL 
  : 'http://localhost:5008'

// API 端点配置
export const API_ENDPOINTS = {
  // 设备状态
  DEVICE_STATUS: `${API_BASE_URL}/api/device_status`,
  
  // 生产数据
  PRODUCTION: `${API_BASE_URL}/api/production`,
  PRODUCTION_DAILY: `${API_BASE_URL}/api/production_daily`,
  
  // 设备数据
  EQUIPMENT: `${API_BASE_URL}/api/equipment`,
  
  // 振动数据
  VIBRATION: `${API_BASE_URL}/api/vibration`,
  REALTIME_VIBRATION: `${API_BASE_URL}/api/realtime_vibration`,
  
  // 工业饼图数据
  INDUSTRIAL_PIE_DATA: `${API_BASE_URL}/api/industrial_pie_data`,
  
  // 实时数据
  REALTIME: `${API_BASE_URL}/api/realtime`,
  
  // 连接状态检查
  CONNECTION_STATUS: `${API_BASE_URL}/api/connection_status`,
}

// 导出默认配置
export default {
  API_BASE_URL,
  API_ENDPOINTS,
}
