import Vue from 'vue'
import Vuex from 'vuex'
import { API_ENDPOINTS } from '@/config'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    // 连接状态统一管理
    edgeConnected: true,
    cloudConnected: true,
    lastDataTime: null,
    dataCount: 0
  },
  mutations: {
    SET_EDGE_CONNECTED(state, connected) {
      state.edgeConnected = connected
    },
    SET_CLOUD_CONNECTED(state, connected) {
      state.cloudConnected = connected
    },
    SET_LAST_DATA_TIME(state, time) {
      state.lastDataTime = time
    },
    SET_DATA_COUNT(state, count) {
      state.dataCount = count
    }
  },
  actions: {
    async checkConnection({ commit }) {
      try {
        // 使用专门的连接状态API，判断数据库是否有新数据
        const response = await fetch(API_ENDPOINTS.CONNECTION_STATUS)
        const data = await response.json()
        
        commit('SET_EDGE_CONNECTED', data.edge_connected)
        commit('SET_CLOUD_CONNECTED', data.cloud_connected)
        
        if (data.edge_connected && data.latest_data_time) {
          commit('SET_LAST_DATA_TIME', new Date(data.latest_data_time))
        }
        
        console.log(`连接状态: 边缘=${data.edge_connected}, 云端=${data.cloud_connected}, 数据量=${data.data_count}`)
      } catch (error) {
        console.error('检查连接失败:', error)
        // 请求失败，云端断开
        commit('SET_CLOUD_CONNECTED', false)
        commit('SET_EDGE_CONNECTED', false)
      }
    },
    startConnectionMonitor({ dispatch }) {
      // 每2秒检查数据库是否有新数据
      setInterval(() => {
        dispatch('checkConnection')
      }, 2000)
      // 立即检查一次
      dispatch('checkConnection')
    }
  },
  modules: {
  }
})
